def _build_directory_tree(self, current: Path, root: Path):
    """Create directory nodes and 'contains' edges."""
    rel = str(current.relative_to(root))
    if rel == ".":
        rel = ""
    dir_id = f"dir::{rel}" if rel else "dir::."

    self.graph.add_node(dir_id, type="directory", name=os.path.basename(str(current)) or str(root.name), path=rel)

    for child in sorted(current.iterdir()):
        if child.name.startswith(".") or child.name == "__pycache__":
            continue
        if child.is_dir():
            child_rel = str(child.relative_to(root))
            child_id = f"dir::{child_rel}"
            self._build_directory_tree(child, root)
            self.graph.add_edge(dir_id, child_id, type="contains")

def _resolve_calls(self, parsed: dict):
    """Resolve function calls to their targets using the symbol table."""
    rel_path = parsed["rel_path"]

    # Build a local import map: short_name -> qualified module path
    import_map: dict[str, str] = {}
    for imp in parsed["imports"]:
        if imp["names"]:
            for name in imp["names"]:
                import_map[name] = f"{imp['module']}.{name}"
        else:
            parts = imp["module"].split(".")
            short = imp["alias"] or parts[-1]
            import_map[short] = imp["module"]

    # Resolve calls in functions
    for func in parsed["functions"]:
        func_id = f"func::{rel_path}::{func['name']}"
        self._resolve_call_list(func_id, func["calls"], import_map)

    # Resolve calls in methods
    for cls in parsed["classes"]:
        for method in cls["methods"]:
            method_id = f"method::{rel_path}::{cls['name']}::{method['name']}"
            self._resolve_call_list(method_id, method["calls"], import_map)

def _resolve_call_list(
    self, caller_id: str, calls: list[str], import_map: dict[str, str]
):
    """Try to resolve each call name to a node in the symbol table."""
    for call_name in calls:
        target_id = self._resolve_single_call(call_name, import_map)
        if target_id and target_id != caller_id:
            self.graph.add_edge(caller_id, target_id, type="calls")

def _resolve_single_call(
    self, call_name: str, import_map: dict[str, str]
) -> str | None:
    """Resolve a single call name to a node ID."""
    # Direct match
    if call_name in self._symbol_table:
        return self._symbol_table[call_name]

    # Try via import map: e.g., "mailer.emails" where "mailer" is imported
    parts = call_name.split(".")
    if parts[0] in import_map:
        qualified = import_map[parts[0]]
        if len(parts) > 1:
            qualified = f"{qualified}.{'.'.join(parts[1:])}"
        if qualified in self._symbol_table:
            return self._symbol_table[qualified]

    # Try just the last part (e.g., "self.emails" -> "emails")
    if len(parts) > 1:
        short = parts[-1]
        if short in self._symbol_table:
            return self._symbol_table[short]

    return None

def _path_to_module(self, rel_path: str) -> str:
    """Convert a file path to a Python module name."""
    module = rel_path.replace(os.sep, ".").replace("/", ".")
    if module.endswith(".py"):
        module = module[:-3]
    if module.endswith(".__init__"):
        module = module[: -len(".__init__")]
    return module

def find(self, name: str, node_type: str | None = None) -> list[dict]:
    """Find nodes by name (substring match) and optional type filter."""
    results = []
    name_lower = name.lower()
    for node_id, data in self.graph.nodes(data=True):
        node_name = data.get("name", "")
        if name_lower not in node_name.lower():
            continue
        if node_type and data.get("type") != node_type:
            continue
        results.append({"id": node_id, **data})
    return results

def callers(self, node_id: str, depth: int = 1) -> list[dict]:
    """Find nodes that call the given node (incoming 'calls' edges).

    With depth > 1, finds transitive callers.
    """
    return self._traverse_edges(node_id, direction="in", edge_type="calls", depth=depth)

def callees(self, node_id: str, depth: int = 1) -> list[dict]:
    """Find nodes that the given node calls (outgoing 'calls' edges).

    With depth > 1, finds transitive callees.
    """
    return self._traverse_edges(node_id, direction="out", edge_type="calls", depth=depth)

def references(self, node_id: str, depth: int = 1) -> list[dict]:
    """Find all nodes connected to the given node, any edge type."""
    return self._traverse_edges(node_id, direction="both", edge_type=None, depth=depth)

def defined_in(self, node_id: str) -> dict | None:
    """Find the file that defines a given node."""
    for pred in self.graph.predecessors(node_id):
        edge_data = self.graph.edges[pred, node_id]
        if edge_data.get("type") == "defines":
            return {"id": pred, **self.graph.nodes[pred]}
    return None

def children(self, node_id: str, node_type: str | None = None) -> list[dict]:
    """Find nodes that this node defines/contains."""
    results = []
    for succ in self.graph.successors(node_id):
        edge_data = self.graph.edges[node_id, succ]
        if edge_data.get("type") not in ("defines", "contains"):
            continue
        data = self.graph.nodes[succ]
        if node_type and data.get("type") != node_type:
            continue
        results.append({"id": succ, **data})
    return results

def stats(self) -> dict:
    """Return summary statistics about the graph."""
    type_counts: dict[str, int] = {}
    edge_type_counts: dict[str, int] = {}

    for _, data in self.graph.nodes(data=True):
        t = data.get("type", "unknown")
        type_counts[t] = type_counts.get(t, 0) + 1

    for _, _, data in self.graph.edges(data=True):
        t = data.get("type", "unknown")
        edge_type_counts[t] = edge_type_counts.get(t, 0) + 1

    return {
        "total_nodes": self.graph.number_of_nodes(),
        "total_edges": self.graph.number_of_edges(),
        "node_types": type_counts,
        "edge_types": edge_type_counts,
    }

def _traverse_edges(
    self,
    start_id: str,
    direction: str,
    edge_type: str | None,
    depth: int,
) -> list[dict]:
    """BFS traversal from a node following edges of a given type/direction."""
    if start_id not in self.graph:
        return []

    visited: set[str] = set()
    results: list[dict] = []
    queue: deque[tuple[str, int]] = deque([(start_id, 0)])

    while queue:
        current, current_depth = queue.popleft()
        if current_depth > 0 and current not in visited:
            visited.add(current)
            node_data = self.graph.nodes[current]
            results.append({
                "id": current,
                "depth": current_depth,
                **node_data,
            })

        if current_depth >= depth:
            continue

        neighbors = self._get_neighbors(current, direction, edge_type)
        for neighbor in neighbors:
            if neighbor not in visited:
                queue.append((neighbor, current_depth + 1))

    return results

def _get_neighbors(
    self, node_id: str, direction: str, edge_type: str | None
) -> list[str]:
    """Get neighbors of a node filtered by direction and edge type."""
    neighbors = []

    if direction in ("in", "both"):
        for pred in self.graph.predecessors(node_id):
            edge_data = self.graph.edges[pred, node_id]
            if edge_type is None or edge_data.get("type") == edge_type:
                neighbors.append(pred)

    if direction in ("out", "both"):
        for succ in self.graph.successors(node_id):
            edge_data = self.graph.edges[node_id, succ]
            if edge_type is None or edge_data.get("type") == edge_type:
                neighbors.append(succ)

    return neighbors

