def _extract_classes(self, tree: ast.Module, source: str) -> list[dict]:
    """Extract class definitions with their bases and methods."""
    classes = []
    for node in ast.iter_child_nodes(tree):
        if not isinstance(node, ast.ClassDef):
            continue
        source_lines = source.splitlines()
        line_start = node.lineno
        line_end = node.end_lineno or node.lineno
        class_source = "\n".join(source_lines[line_start - 1 : line_end])

        methods = []
        for item in ast.walk(node):
            if isinstance(item, (ast.FunctionDef, ast.AsyncFunctionDef)):
                methods.append({
                    "name": item.name,
                    "line_start": item.lineno,
                    "line_end": item.end_lineno or item.lineno,
                    "calls": self._extract_calls(item),
                    "args": [arg.arg for arg in item.args.args],
                })

        classes.append({
            "name": node.name,
            "line_start": line_start,
            "line_end": line_end,
            "source": class_source,
            "bases": [self._node_name(b) for b in node.bases],
            "methods": methods,
            "decorators": [self._decorator_name(d) for d in node.decorator_list],
        })
    return classes

def _extract_imports(self, tree: ast.Module) -> list[dict]:
    """Extract import and from-import statements."""
    imports = []
    for node in ast.iter_child_nodes(tree):
        if isinstance(node, ast.Import):
            for alias in node.names:
                imports.append({
                    "module": alias.name,
                    "names": [],
                    "alias": alias.asname,
                    "line": node.lineno,
                })
        elif isinstance(node, ast.ImportFrom):
            imports.append({
                "module": node.module or "",
                "names": [a.name for a in node.names],
                "alias": None,
                "line": node.lineno,
            })
    return imports

def _extract_variables(self, tree: ast.Module) -> list[dict]:
    """Extract top-level variable assignments."""
    variables = []
    for node in ast.iter_child_nodes(tree):
        if isinstance(node, ast.Assign):
            for target in node.targets:
                if isinstance(target, ast.Name):
                    variables.append({
                        "name": target.id,
                        "line": node.lineno,
                    })
        elif isinstance(node, ast.AnnAssign) and isinstance(
            node.target, ast.Name
        ):
            variables.append({
                "name": node.target.id,
                "line": node.lineno,
            })
    return variables

def _extract_calls(self, node: ast.AST) -> list[str]:
    """Extract all function/method call names within a node."""
    calls = []
    for child in ast.walk(node):
        if not isinstance(child, ast.Call):
            continue
        name = self._call_name(child)
        if name:
            calls.append(name)
    return calls

def _call_name(self, node: ast.Call) -> str | None:
    """Get the name of a function call."""
    if isinstance(node.func, ast.Name):
        return node.func.id
    if isinstance(node.func, ast.Attribute):
        value_name = self._node_name(node.func.value)
        if value_name:
            return f"{value_name}.{node.func.attr}"
        return node.func.attr
    return None

def _node_name(self, node: ast.AST) -> str | None:
    """Get a string name from an AST node."""
    if isinstance(node, ast.Name):
        return node.id
    if isinstance(node, ast.Attribute):
        value = self._node_name(node.value)
        if value:
            return f"{value}.{node.attr}"
        return node.attr
    return None

def _decorator_name(self, node: ast.AST) -> str:
    """Get the name of a decorator."""
    if isinstance(node, ast.Name):
        return node.id
    if isinstance(node, ast.Attribute):
        return self._node_name(node) or ""
    if isinstance(node, ast.Call):
        return self._node_name(node.func) or ""
    return ""

class PythonParser:
    """Parses a Python file and extracts code entities and relationships."""

    def parse_file(self, filepath: str) -> dict | None:
        """Parse a single Python file and return extracted entities.

        Returns None if the file cannot be parsed.
        """
        filepath = Path(filepath)
        try:
            source = filepath.read_text(encoding="utf-8", errors="replace")
            tree = ast.parse(source, filename=str(filepath))
        except (SyntaxError, UnicodeDecodeError):
            return None

        return {
            "file": str(filepath),
            "functions": self._extract_functions(tree, source),
            "classes": self._extract_classes(tree, source),
            "imports": self._extract_imports(tree),
            "variables": self._extract_variables(tree),
        }

    def _extract_functions(self, tree: ast.Module, source: str) -> list[dict]:
        """Extract top-level and nested function definitions."""
        functions = []
        for node in ast.walk(tree):
            if not isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                continue
            source_lines = source.splitlines()
            line_start = node.lineno
            line_end = node.end_lineno or node.lineno
            func_source = "\n".join(source_lines[line_start - 1 : line_end])

            functions.append({
                "name": node.name,
                "line_start": line_start,
                "line_end": line_end,
                "source": func_source,
                "calls": self._extract_calls(node),
                "args": [arg.arg for arg in node.args.args],
                "decorators": [self._decorator_name(d) for d in node.decorator_list],
            })
        return functions

    def _extract_classes(self, tree: ast.Module, source: str) -> list[dict]:
        """Extract class definitions with their bases and methods."""
        classes = []
        for node in ast.iter_child_nodes(tree):
            if not isinstance(node, ast.ClassDef):
                continue
            source_lines = source.splitlines()
            line_start = node.lineno
            line_end = node.end_lineno or node.lineno
            class_source = "\n".join(source_lines[line_start - 1 : line_end])

            methods = []
            for item in ast.walk(node):
                if isinstance(item, (ast.FunctionDef, ast.AsyncFunctionDef)):
                    methods.append({
                        "name": item.name,
                        "line_start": item.lineno,
                        "line_end": item.end_lineno or item.lineno,
                        "calls": self._extract_calls(item),
                        "args": [arg.arg for arg in item.args.args],
                    })

            classes.append({
                "name": node.name,
                "line_start": line_start,
                "line_end": line_end,
                "source": class_source,
                "bases": [self._node_name(b) for b in node.bases],
                "methods": methods,
                "decorators": [self._decorator_name(d) for d in node.decorator_list],
            })
        return classes

    def _extract_imports(self, tree: ast.Module) -> list[dict]:
        """Extract import and from-import statements."""
        imports = []
        for node in ast.iter_child_nodes(tree):
            if isinstance(node, ast.Import):
                for alias in node.names:
                    imports.append({
                        "module": alias.name,
                        "names": [],
                        "alias": alias.asname,
                        "line": node.lineno,
                    })
            elif isinstance(node, ast.ImportFrom):
                imports.append({
                    "module": node.module or "",
                    "names": [a.name for a in node.names],
                    "alias": None,
                    "line": node.lineno,
                })
        return imports

    def _extract_variables(self, tree: ast.Module) -> list[dict]:
        """Extract top-level variable assignments."""
        variables = []
        for node in ast.iter_child_nodes(tree):
            if isinstance(node, ast.Assign):
                for target in node.targets:
                    if isinstance(target, ast.Name):
                        variables.append({
                            "name": target.id,
                            "line": node.lineno,
                        })
            elif isinstance(node, ast.AnnAssign) and isinstance(
                node.target, ast.Name
            ):
                variables.append({
                    "name": node.target.id,
                    "line": node.lineno,
                })
        return variables

    def _extract_calls(self, node: ast.AST) -> list[str]:
        """Extract all function/method call names within a node."""
        calls = []
        for child in ast.walk(node):
            if not isinstance(child, ast.Call):
                continue
            name = self._call_name(child)
            if name:
                calls.append(name)
        return calls

    def _call_name(self, node: ast.Call) -> str | None:
        """Get the name of a function call."""
        if isinstance(node.func, ast.Name):
            return node.func.id
        if isinstance(node.func, ast.Attribute):
            value_name = self._node_name(node.func.value)
            if value_name:
                return f"{value_name}.{node.func.attr}"
            return node.func.attr
        return None

    def _node_name(self, node: ast.AST) -> str | None:
        """Get a string name from an AST node."""
        if isinstance(node, ast.Name):
            return node.id
        if isinstance(node, ast.Attribute):
            value = self._node_name(node.value)
            if value:
                return f"{value}.{node.attr}"
            return node.attr
        return None

    def _decorator_name(self, node: ast.AST) -> str:
        """Get the name of a decorator."""
        if isinstance(node, ast.Name):
            return node.id
        if isinstance(node, ast.Attribute):
            return self._node_name(node) or ""
        if isinstance(node, ast.Call):
            return self._node_name(node.func) or ""
        return ""

def save(self, graph: nx.DiGraph, filepath: str):
    """Save the graph to a JSON file."""
    path = Path(filepath)
    path.parent.mkdir(parents=True, exist_ok=True)

    data = {
        "nodes": [],
        "edges": [],
    }

    for node_id, attrs in graph.nodes(data=True):
        node = {"id": node_id}
        node.update(attrs)
        data["nodes"].append(node)

    for src, dst, attrs in graph.edges(data=True):
        edge = {"source": src, "target": dst}
        edge.update(attrs)
        data["edges"].append(edge)

    path.write_text(json.dumps(data, indent=2, default=str), encoding="utf-8")

class JsonStore:
    """Persist a NetworkX graph to a JSON file."""

    def save(self, graph: nx.DiGraph, filepath: str):
        """Save the graph to a JSON file."""
        path = Path(filepath)
        path.parent.mkdir(parents=True, exist_ok=True)

        data = {
            "nodes": [],
            "edges": [],
        }

        for node_id, attrs in graph.nodes(data=True):
            node = {"id": node_id}
            node.update(attrs)
            data["nodes"].append(node)

        for src, dst, attrs in graph.edges(data=True):
            edge = {"source": src, "target": dst}
            edge.update(attrs)
            data["edges"].append(edge)

        path.write_text(json.dumps(data, indent=2, default=str), encoding="utf-8")

    def load(self, filepath: str) -> nx.DiGraph:
        """Load a graph from a JSON file."""
        path = Path(filepath)
        raw = json.loads(path.read_text(encoding="utf-8"))

        graph = nx.DiGraph()

        for node in raw["nodes"]:
            node_id = node.pop("id")
            graph.add_node(node_id, **node)

        for edge in raw["edges"]:
            src = edge.pop("source")
            dst = edge.pop("target")
            graph.add_edge(src, dst, **edge)

        return graph
